  1→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  2→import './notification.css';
  3→import { useAuth } from '../../Context/useAuth';
  4→import { MoonLoader } from 'react-spinners';
  5→import { useEffect, useRef, useState } from 'react';
  6→import NotificationCards from './notificationsCards';
  7→import { AnimatePresence, motion } from 'framer-motion';
  8→import { Outlet, useLocation, useNavigate } from 'react-router-dom';
  9→
 10→const Notifications = () =>{
 11→    const scrollRef = useRef();
 12→    const navigate = useNavigate();
 13→    const location = useLocation();
 14→
 15→    const {user, session} = useAuth();
 16→    const [showHeader, setShowHeader] = useState(true);
 17→
 18→    const notificationLinks =[
 19→        {
 20→            className: 'all-notification-container',
 21→            label: 'All',
 22→            pathname: '/home/notifications',
 23→            action: () => navigate('/home/notifications')
 24→        },
 25→        {
 26→            className: 'unread-notification-container',
 27→            label: 'Unread notifications',
 28→            pathname: '/home/notifications/unreadNotification',
 29→            action: () => navigate('/home/notifications/unreadNotification')
 30→        }
 31→    ]
 32→
 33→    const handleClickBack = (e) =>{
 34→        e.stopPropagation();
 35→        window.history.back();
 36→    }
 37→
 38→    useEffect(() =>{
 39→        const scroll = () =>{
 40→            setShowHeader(false);
 41→            if(scrollRef.current){
 42→                clearTimeout(scrollRef.current);   
 43→            }
 44→            scrollRef.current = setTimeout(() => {
 45→                setShowHeader(true)
 46→            }, 500);
 47→        }
 48→        document.addEventListener('scroll', scroll, true);
 49→        return () => {
 50→            if(scrollRef.current){
 51→                clearTimeout(scrollRef.current)
 52→            }
 53→            document.removeEventListener('scroll', scroll, true)
 54→        }
 55→    })
 56→
 57→    return(
 58→        <>
 59→        {showHeader && (
 60→            <AnimatePresence>
 61→            <motion.div 
 62→            className='notifications-header'
 63→            initial={{opacity: 0}}
 64→            animate={{opacity: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
 65→            exit={{ opacity: 0, y: -20,
 66→                    transition: { 
 67→                    duration: 0.2,
 68→                    ease: "easeOut"
 69→                    }
 70→            }}
 71→            >   
 72→                <div className='first-container'>
 73→                    <div onClick={(e) => handleClickBack(e)} className='back-button'>
 74→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="#000000"><path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z"/></svg>
 75→                    </div>
 76→            
 77→                    <p className='notifications-header-text'>Notifications</p>
 78→                </div> 
 79→
 80→                <div className='second-container'>
 81→                    {notificationLinks.map((link, index) => (
 82→                        <div onClick={() => link.action()} key={index} className={link.className}>
 83→                            <p style={{margin: 0, padding: 0, fontWeight: 560}}>{link.label}</p>
 84→                            <div className={location.pathname === link.pathname ? 'tab-indicator' : ''}>
 85→
 86→                            </div>
 87→                        </div>
 88→                    ))}
 89→                    
 90→                </div>
 91→            </motion.div>
 92→            </AnimatePresence>
 93→        )}
 94→
 95→        {/* create a notification cards component here! */}
 96→
 97→        <Outlet/>
 98→        </>
 99→    )
100→}
101→
102→export default Notifications;

