132→        getNextPageParam: (lastpage) =>{
133→            if(lastpage?.hasMore){
134→                const lastNotification = lastpage?.data[lastpage?.data.length - 1];
135→                return new Date(lastNotification.created_at).toISOString();
136→
137→            }
138→            return undefined;
139→        },
140→        enabled: !!session?.access_token,
141→        refetchOnWindowFocus: false
142→    })
143→
144→    useEffect(() =>{
145→        if(scrollToTop.current && !isLoading){
146→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
147→        }
148→    }, [isLoading])
