773→export const getMonthlyHottestJournalsService = async(limit, userId) => {
774→    if(isNaN(limit) || limit < 1 || limit > 10){
775→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
776→    }
777→
778→    const parsedLimit = parseInt(limit);
779→    const now = new Date();
