781→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
782→
783→    const {data: journals, error: journalsError} = await supabase
784→        .from('journals')
785→        .select(JOURNAL_WITH_COUNTS_SELECT)
786→        .eq('privacy', 'public')
787→        .gte('created_at', monthStartUtc.toISOString())
788→        .lt('created_at', nextMonthStartUtc.toISOString());
789→
790→    if(journalsError){
791→        console.error('supabase error while fetching monthly hottest journals:', journalsError.message);
792→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
793→    }
794→
795→    const journalsWithInteractions = await attachUserInteractionFlags(journals || [], userId);
796→    const scored = journalsWithInteractions.map((journal) => {
797→        const likes = journal?.like_count?.[0]?.count || 0;
798→        const comments = journal?.comment_count?.[0]?.count || 0;
799→        const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
800→        const views = journal?.views || 0;
