812→            return scoreDiff;
813→        }
814→
815→        const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
816→        if(dateDiff !== 0){
817→            return dateDiff;
818→        }
819→
820→        return (b?.id || 0) - (a?.id || 0);
821→    });
822→
823→    return {
824→        data: scored.slice(0, parsedLimit),
825→        period: {
826→            startUtc: monthStartUtc.toISOString(),
827→            endUtc: nextMonthStartUtc.toISOString(),
828→            timezone: 'UTC'
829→        },
830→        totalCandidates: scored.length
